import { moduleMetadata } from '@storybook/angular';
import { LucideAngularModule, Send, Undo2, Trash2 } from 'lucide-angular';
import { PfButtonComponent } from './button.component';
const meta = {
    title: 'Composants graphiques/Button',
    component: PfButtonComponent,
    tags: ['autodocs'],
    parameters: {
        docs: {
            description: {
                component: "Élément d'interaction principal. 4 variantes, 3 tailles, bloc, désactivé. [→ Description complète & bonnes pratiques](?path=/docs/documentation-générale-composants-graphiques-button--docs)",
            },
        },
    },
    argTypes: {
        variant: {
            control: 'select',
            options: ['primary', 'secondary', 'ghost', 'danger'],
        },
        size: {
            control: 'inline-radio',
            options: ['sm', 'md', 'lg'],
        },
        block: { control: 'boolean' },
        disabled: { control: 'boolean' },
        label: {
            control: 'text',
            description: 'Texte projeté dans le bouton (ng-content).',
        },
    },
    args: {
        variant: 'primary',
        size: 'md',
        block: false,
        disabled: false,
        label: 'Envoyer',
    },
    render: (args) => ({
        props: args,
        template: `<pf-button
      [variant]="variant"
      [size]="size"
      [block]="block"
      [disabled]="disabled"
    >{{ label }}</pf-button>`,
    }),
};
export default meta;
export const Primary = {};
export const Secondary = { args: { variant: 'secondary' } };
export const Ghost = { args: { variant: 'ghost' } };
export const Danger = { args: { variant: 'danger', label: 'Supprimer' } };
export const Disabled = { args: { disabled: true, label: 'Désactivé' } };
export const Sizes = {
    render: (args) => ({
        props: args,
        template: `
      <div style="display: flex; gap: 1rem; align-items: center;">
        <pf-button [variant]="variant" size="sm">Petit</pf-button>
        <pf-button [variant]="variant" size="md">Moyen</pf-button>
        <pf-button [variant]="variant" size="lg">Grand</pf-button>
      </div>
    `,
    }),
};
export const AllVariants = {
    render: () => ({
        template: `
      <div style="display: flex; gap: 1rem; flex-wrap: wrap;">
        <pf-button variant="primary">Primary</pf-button>
        <pf-button variant="secondary">Secondary</pf-button>
        <pf-button variant="ghost">Ghost</pf-button>
        <pf-button variant="danger">Danger</pf-button>
        <pf-button variant="primary" [disabled]="true">Disabled</pf-button>
      </div>
    `,
    }),
};
export const Block = {
    args: { block: true, label: 'Bouton pleine largeur' },
    decorators: [
        (storyFn) => {
            const story = storyFn();
            return {
                ...story,
                template: `<div style="width: 320px;">${story.template}</div>`,
            };
        },
    ],
};
/**
 * Démo de composition : le bouton accepte n'importe quel contenu projeté,
 * y compris des icônes Lucide via lucide-icon.
 */
export const Composition = {
    decorators: [moduleMetadata({ imports: [LucideAngularModule] })],
    render: () => ({
        props: { SendIcon: Send, UndoIcon: Undo2, TrashIcon: Trash2 },
        template: `
      <div style="display: flex; gap: 1rem; flex-wrap: wrap;">
        <pf-button variant="primary">
          <lucide-icon [img]="SendIcon" [size]="16"></lucide-icon>
          Envoyer
        </pf-button>
        <pf-button variant="secondary">
          <lucide-icon [img]="UndoIcon" [size]="16"></lucide-icon>
          Retour
        </pf-button>
        <pf-button variant="danger">
          <lucide-icon [img]="TrashIcon" [size]="16"></lucide-icon>
          Supprimer
        </pf-button>
      </div>
    `,
    }),
};
